74	func (r *resourceSource) assignSiteVector(vec sitesmatrix.Vector) *resourceSource {
75		if r.state == resourceStateAssigned {
76			panic("cannot assign site vector to a resourceSource that is already assigned")
77		}
78		r.sv = vec
79		r.state = resourceStateAssigned
80		return r
81	}
