97	func (r *resourceSource) String() string {
98		var sb strings.Builder
99		if r.fi != nil {
100			sb.WriteString("filename: " + r.fi.Meta().Filename)
101			sb.WriteString(fmt.Sprintf(" matrix: %v", r.fi.Meta().SitesMatrix))
102			sb.WriteString(fmt.Sprintf(" complements: %v", r.fi.Meta().SitesComplements))
103		}
104		if r.rc != nil {
105			sb.WriteString(fmt.Sprintf("rc matrix: %v", r.rc.SitesMatrix))
106			sb.WriteString(fmt.Sprintf("rc complements: %v", r.rc.SitesComplements))
107		}
108		sb.WriteString(fmt.Sprintf(" sv: %v", r.sv))
109		return sb.String()
110	}
