143	func (p *resourceSource) lookupContentNode(v sitesmatrix.Vector) contentNode {
144		if p.state >= resourceStateAssigned {
145			if p.sv == v {
146				return p
147			}
148			return nil
149		}
150	
151		// A site has not been assigned yet.
152	
153		if p.rc != nil && p.rc.MatchSiteVector(v) {
154			return p
155		}
156	
157		if p.rc != nil && p.rc.SitesMatrix.LenVectors() > 0 {
158			// Do not consider file mount matrix if the resource config has its own.
159			return nil
160		}
161	
162		if p.fi != nil && p.fi.Meta().SitesMatrix.HasVector(v) {
163			return p
164		}
165	
166		return nil
167	}
168	
169	func (p *resourceSource) lookupContentNodes(siteVector sitesmatrix.Vector, fallback bool) iter.Seq[contentNodeForSite] {
170		if siteVector == p.sv {
171			found := p.rc == nil
172			if !found {
173				// For content adapter resources with explicit sites.matrix config,
174				// verify the vector is allowed even on exact match,
175				// since sv is the creating site's vector, not necessarily the target.
176				// In the exact-match path (siteVector == p.sv), always use strict matching.
177				// The coarse language-excluding fallback only applies for cross-site matching.
178				found = p.rc.Sites.Matrix.IsZero() || p.rc.MatchSiteVector(siteVector)
179			}
180			if !found {
181				return nil
182			}
183	
184			return func(yield func(n contentNodeForSite) bool) {
185				yield(p)
186			}
187		}
188	
189		pc := p.rc
190	
191		var found bool
192		if !fallback {
193			if pc != nil && pc.MatchSiteVector(siteVector) {
194				found = true
195			} else {
196				return nil
197			}
198		}
199	
200		if !found {
201			if pc != nil {
202				// Content adapter resources have explicit site matrix config; respect all dimensions.
203				found = pc.MatchSiteVectorCoarse(siteVector)
204			} else if p.fi != nil {
205				// File-based resources: exclude the language dimension in the coarse match.
206				// The typical setup is to provide translated content files but one resource (e.g. an image) that is shared between the translations.
207				// To give all the languages a full set, we ignore that dimension for this last fallback check.
208				found = p.fi.Meta().MatchSiteVectorCoarseExcludeLanguage(siteVector)
209			}
210		}
211	
212		if !found {
213			return nil
214		}
215	
216		return func(yield func(n contentNodeForSite) bool) {
217			if !yield(p) {
218				return
219			}
220		}
221	}
