972		w := &doctree.NodeShiftTreeWalker[contentNode]{
973			Tree: s.pageMap.treePages,
974			Handle: func(key string, n contentNode) (radix.WalkFlag, error) {
975				if p, ok := n.(*pageState); ok {
976					for _, f := range p.m.pageConfig.ConfiguredOutputFormats {
977						if !formatSet[f.Name] {
978							formats = append(formats, f)
979							formatSet[f.Name] = true
980						}
981					}
982				}
983				return radix.WalkContinue, nil
984			},
985		}
986	
987		if err := w.Walk(context.TODO()); err != nil {
988			panic(err)
989		}
990	
991		// Add the per kind configured output formats
992		for _, kind := range kinds.AllKindsInPages {
993			if siteFormats, found := s.conf.C.KindOutputFormats[kind]; found {
994				for _, f := range siteFormats {
995					if !formatSet[f.Name] {
996						formats = append(formats, f)
997						formatSet[f.Name] = true
998					}
999				}

175	
176			templ, found, err := p.resolveTemplate()
177			if err != nil {
178				if sendErr(p.errorf(err, "failed to resolve template")) {
179					continue
180				} else {
181					return
182				}
183			}
184	
185			if !found {
186				s.Log.Trace(
187					func() string {
188						return fmt.Sprintf("no layout for kind %q found", p.Kind())
189					},
190				)
191				// Don't emit warning for missing 404 etc. pages.
192				if !p.m.isStandalone() {
193					s.logMissingLayout("", p.Layout(), p.Kind(), p.f.Name)
194				}
195				continue
196			}
197	
198			targetPath := p.targetPaths().TargetFilename
199	
200			s.Log.Trace(
201				func() string {
202					return fmt.Sprintf("rendering outputFormat %q kind %q using layout %q to %q", p.pageOutput.f.Name, p.Kind(), templ.Name(), targetPath)
203				},
204			)
205	
206			var d any = p
207			switch p.Kind() {
208			case kinds.KindSitemapIndex:
209				d = s.h.Sites
210			}
211	
212			if err := s.renderAndWritePage(&s.PathSpec.ProcessingStats.Pages, targetPath, p, d, templ); err != nil {
213				if sendErr(err) {
214					continue
215				} else {
216					return
217				}
218			}
219	
220			if of := p.outputFormat(); p.IsHome() && of.IsHTML && s.isDefault() && (of.Path != "" || of.Name == "html") {
221				if err = s.renderDefaultSiteRedirect(p); err != nil {
222					if sendErr(err) {
223						continue
224					} else {
225						return
