653	// Must be run after the site section tree etc. is built and ready.
654	func (ps *pageState) initPage() error {
655		var initErr error
656		ps.pageInit.Do(func() {
657			var pp pagePaths
658			pp, initErr = newPagePaths(ps)
659			if initErr != nil {
660				return
661			}
662	
663			var outputFormatsForPage output.Formats
664			var renderFormats output.Formats
665	
666			if ps.m.standaloneOutputFormat.IsZero() {
667				outputFormatsForPage = ps.outputFormats()
668				renderFormats = ps.s.h.renderFormats
669			} else {
670				// One of the fixed output format pages, e.g. 404.
671				outputFormatsForPage = output.Formats{ps.m.standaloneOutputFormat}
672				renderFormats = outputFormatsForPage
673			}
674	
675			// Prepare output formats for all sites.
676			// We do this even if this page does not get rendered on
677			// its own. It may be referenced via one of the site collections etc.
678			// it will then need an output format.
679			ps.pageOutputs = make([]*pageOutput, len(renderFormats))
680			created := make(map[string]*pageOutput)
681			shouldRenderPage := !ps.m.noRender()
682	
683			for i, f := range renderFormats {
684	
685				if po, found := created[f.Name]; found {
686					ps.pageOutputs[i] = po
687					continue
688				}
689	
690				render := shouldRenderPage
691				if render {
692					_, render = outputFormatsForPage.GetByName(f.Name)
693				}
694	
695				po := newPageOutput(ps, pp, f, render)
696	
697				// Create a content provider for the first,
698				// we may be able to reuse it.
699				if i == 0 {
700					var contentProvider *pageContentOutput
701					contentProvider, initErr = newPageContentOutput(po)
702					if initErr != nil {
703						return
704					}
705					po.setContentProvider(contentProvider)
706				}
707	
708				ps.pageOutputs[i] = po
709				created[f.Name] = po
710	
711			}
712	
713			if initErr = ps.initCommonProviders(pp); initErr != nil {
714				return
715			}
716		})
717	
718		return initErr
719	}
