828		args := append([]any{ps.Language().Lang, ps.pathOrTitle()}, a...)
829		args = append(args, err)
830		format = "[%s] page %q: " + format + ": %w"
831		if err == nil {
832			return fmt.Errorf(format, args...)
833		}
834		return fmt.Errorf(format, args...)
