242	func (s *Site) logMissingLayout(name, layout, kind, outputFormat string) {
243		log := s.Log.Warn()
244		if name != "" && infoOnMissingLayout[name] {
245			log = s.Log.Info()
246		}
247	
248		errMsg := "You should create a template file which matches Hugo Layouts Lookup Rules for this combination."
249		var args []any
250		msg := "found no layout file for"
251		if outputFormat != "" {
252			msg += " %q"
253			args = append(args, outputFormat)
254		}
255	
256		if layout != "" {
257			msg += " for layout %q"
258			args = append(args, layout)
259		}
260	
261		if kind != "" {
262			msg += " for kind %q"
263			args = append(args, kind)
264		}
265	
266		if name != "" {
267			msg += " for %q"
268			args = append(args, name)
269		}
270	
271		msg += ": " + errMsg
272	
273		log.Logf(msg, args...)
274	}
