300	// assemble creates missing sections, applies aggregate values (e.g. dates, cascading params),
301	// removes disabled pages etc.
302	func (h *HugoSites) assemble(ctx context.Context, l logg.LevelLogger, bcfg *BuildCfg) error {
303		l = l.WithField("step", "assemble")
304		defer loggers.TimeTrackf(l, time.Now(), nil, "")
305	
306		if !bcfg.WhatChanged.needsPagesAssembly {
307			changes := bcfg.WhatChanged.Drain()
308			if len(changes) > 0 {
309				if err := h.resolveAndClearStateForIdentities(ctx, l, nil, changes); err != nil {
310					return err
311				}
312			}
313			return nil
314		}
315	
316		h.translationKeyPages.Reset()
317	
318		var assemblers []*sitePagesAssembler
319		// Changes detected during assembly (e.g. aggregate date changes)
320		for s := range h.allSites(nil) {
321			assemblers = append(assemblers, &sitePagesAssembler{
322				s:               s,
323				assembleChanges: bcfg.WhatChanged,
324				ctx:             ctx,
325			})
326		}
327	
328		apa := newAllPagesAssembler(
329			ctx,
330			h,
331			assemblers[0].s.pageMap,
332			bcfg.WhatChanged,
333		)
334		for _, s := range assemblers {
335			s.a = apa
336		}
337	
338		if h.Conf.Watching() {
339			defer func() {
340				// Store previous walk context to detect cascade changes on next rebuild.
341				h.previousPageTreesWalkContext = apa.rwRoot.WalkContext
342			}()
343		}
344	
345		if err := apa.createAllPages(); err != nil {
346			return err
347		}
348	
349		g, _ := h.workersSite.Start(ctx)
350		for _, s := range assemblers {
351			g.Run(func() error {
352				return s.assemblePagesStep1()
353			})
354		}
355		if err := g.Wait(); err != nil {
356			return err
357		}
358	
359		changes := bcfg.WhatChanged.Drain()
360	
361		// Changes from the assemble step (e.g. lastMod, cascade) needs a re-calculation
362		// of what needs to be re-built.
363		if len(changes) > 0 {
364			if err := h.resolveAndClearStateForIdentities(ctx, l, nil, changes); err != nil {
365				return err
366			}
367		}
368	
369		for _, s := range assemblers {
370			if err := s.assemblePagesStep2(); err != nil {
371				return err
372			}
373		}
374	
375		// Handle new terms from assemblePagesStep2.
376		changes = bcfg.WhatChanged.Drain()
377		if len(changes) > 0 {
378			if err := h.resolveAndClearStateForIdentities(ctx, l, nil, changes); err != nil {
379				return err
380			}
381		}
382	
383		h.renderFormats = output.Formats{}
384		for s := range h.allSites(nil) {
385			s.initRenderFormats()
386			h.renderFormats = append(h.renderFormats, s.renderFormats...)
387		}
388	
389		for _, s := range assemblers {
390			if err := s.assemblePagesStepFinal(); err != nil {
391				return err
392			}
393		}
394	
395		return nil
396	}
