649	// postProcess runs the post processors, e.g. writing the hugo_stats.json file.
650	func (h *HugoSites) postProcess(l logg.LevelLogger) error {
651		l = l.WithField("step", "postProcess")
652		defer loggers.TimeTrackf(l, time.Now(), nil, "")
653	
654		// This will only be set when js.Build have been triggered with
655		// imports that resolves to the project or a module.
656		// Write a jsconfig.json file to the project's /asset directory
657		// to help JS IntelliSense in VS Code etc.
658		if !h.ResourceSpec.BuildConfig().NoJSConfigInAssets {
659			handleJSConfig := func(fi os.FileInfo) {
660				m := fi.(hugofs.FileMetaInfo).Meta()
661				if !m.IsProject {
662					return
663				}
664	
665				if jsConfig := h.ResourceSpec.JSConfigBuilder.Build(m.SourceRoot); jsConfig != nil {
666					b, err := json.MarshalIndent(jsConfig, "", " ")
667					if err != nil {
668						h.Log.Warnf("Failed to create jsconfig.json: %s", err)
669					} else {
670						filename := filepath.Join(m.SourceRoot, "jsconfig.json")
671						if h.Configs.Base.Internal.Running {
672							h.skipRebuildForFilenamesMu.Lock()
673							h.skipRebuildForFilenames[filename] = true
674							h.skipRebuildForFilenamesMu.Unlock()
675						}
676						// Make sure it's  written to the OS fs as this is used by
677						// editors.
678						if err := afero.WriteFile(hugofs.Os, filename, b, 0o666); err != nil {
679							h.Log.Warnf("Failed to write jsconfig.json: %s", err)
680						}
681					}
682				}
683			}
684	
685			fi, err := h.BaseFs.Assets.Fs.Stat("")
686			if err != nil {
687				if !herrors.IsNotExist(err) {
688					h.Log.Warnf("Failed to resolve jsconfig.json dir: %s", err)
689				}
690			} else {
691				handleJSConfig(fi)
692			}
693		}
694	
695		var toPostProcess []postpub.PostPublishedResource
696		for _, r := range h.ResourceSpec.PostProcessResources.All() {
697			toPostProcess = append(toPostProcess, r)
698		}
699	
700		if len(toPostProcess) == 0 {
701			// Nothing more to do.
702			return nil
703		}
704	
705		workers := para.New(config.GetNumWorkerMultiplier())
706		g, _ := workers.Start(context.Background())
707	
708		handleFile := func(filename string) error {
709			content, err := afero.ReadFile(h.BaseFs.PublishFs, filename)
710			if err != nil {
711				return err
712			}
713	
714			k := 0
715			changed := false
716	
717			for {
718				l := bytes.Index(content[k:], []byte(postpub.PostProcessPrefix))
719				if l == -1 {
720					break
721				}
722				m := bytes.Index(content[k+l:], []byte(postpub.PostProcessSuffix)) + len(postpub.PostProcessSuffix)
723	
724				low, high := k+l, k+l+m
725	
726				field := content[low:high]
727	
728				forward := l + m
729	
730				for i, r := range toPostProcess {
731					if r == nil {
732						panic(fmt.Sprintf("resource %d to post process is nil", i+1))
733					}
734					v, ok := r.GetFieldString(string(field))
735					if ok {
736						content = append(content[:low], append([]byte(v), content[high:]...)...)
737						changed = true
738						forward = len(v)
739						break
740					}
741				}
742	
743				k += forward
744			}
745	
746			if changed {
747				return afero.WriteFile(h.BaseFs.PublishFs, filename, content, 0o666)
748			}
749	
750			return nil
751		}
752	
753		filenames := h.Deps.BuildState.GetFilenamesWithPostPrefix()
754		for _, filename := range filenames {
755			g.Run(func() error {
756				return handleFile(filename)
757			})
758		}
759	
760		// Prepare for a new build.
761		for _, s := range h.Sites {
762			s.ResourceSpec.PostProcessResources = maphelpers.NewConcurrentMap[string, postpub.PostPublishedResource]()
763		}
764	
765		return g.Wait()
766	}
767	
768	func (h *HugoSites) writeBuildStats() error {
769		if h.ResourceSpec == nil {
770			panic("h.ResourceSpec is nil")
771		}
772		if !h.ResourceSpec.BuildConfig().BuildStats.Enabled() {
773			return nil
774		}
775	
776		htmlElements := &publisher.HTMLElements{}
777		for _, s := range h.Sites {
778			stats := s.publisher.PublishStats()
779			htmlElements.Merge(stats.HTMLElements)
780		}
781	
782		filename := filepath.Join(h.Configs.LoadingInfo.BaseConfig.WorkingDir, files.FilenameHugoStatsJSON)
783	
784		existingContent, _ := afero.ReadFile(hugofs.Os, filename)
785	
786		// When rendering only a subset of the site, merge with any existing
787		// hugo_stats.json so that elements from pages not rendered in this build
788		// are preserved (e.g. so Tailwind doesn't strip their classes).
789		// See issue 14939.
790		if len(h.Configs.Base.RenderSegments) > 0 && len(existingContent) > 0 {
791			var existing publisher.PublishStats
792			if err := json.Unmarshal(existingContent, &existing); err == nil {
793				htmlElements.Merge(existing.HTMLElements)
794			} else {
795				h.Log.Warnf("Failed to unmarshal existing hugo_stats.json: %s", err)
796			}
797		}
798	
799		htmlElements.Sort()
800	
801		stats := publisher.PublishStats{
802			HTMLElements: *htmlElements,
803		}
804	
805		var buf bytes.Buffer
806		enc := json.NewEncoder(&buf)
807		enc.SetEscapeHTML(false)
808		enc.SetIndent("", "  ")
809		err := enc.Encode(stats)
810		if err != nil {
811			return err
812		}
813		js := buf.Bytes()
814	
815		if bytes.Equal(existingContent, js) {
816			return nil
817		}
818	
819		// Make sure it's always written to the OS fs.
820		if err := afero.WriteFile(hugofs.Os, filename, js, 0o666); err != nil {
821			return err
822		}
823	
824		// Write to the destination as well if it's a in-memory fs.
825		if !hugofs.IsOsFs(h.Fs.Source) {
826			if err := afero.WriteFile(h.Fs.WorkingDirWritable, filename, js, 0o666); err != nil {
827				return err
828			}
829		}
830	
831		// This step may be followed by a post process step that may
832		// rebuild e.g. CSS, so clear any cache that's defined for the hugo_stats.json.
833		h.dynacacheGCFilenameIfNotWatchedAndDrainMatching(filename)
834	
835		return nil
836	}
