864	// processPartialFileEvents prepares the Sites' sources for a partial rebuild.
865	func (h *HugoSites) processPartialFileEvents(ctx context.Context, l logg.LevelLogger, config *BuildCfg, init func(config *BuildCfg) error, events []fsnotify.Event) error {
866		h.Log.Trace(logg.StringFunc(func() string {
867			var sb strings.Builder
868			sb.WriteString("File events:\n")
869			for _, ev := range events {
870				sb.WriteString(ev.String())
871				sb.WriteString("\n")
872			}
873			return sb.String()
874		}))
875	
876		// For a list of events for the different OSes, see the test output in https://github.com/bep/fsnotifyeventlister/.
877		events = h.fileEventsFilter(events)
878		events = h.fileEventsTrim(events)
879		eventInfos := h.fileEventsApplyInfo(events)
880	
881		logger := h.Log
882	
883		var (
884			tmplAdded          bool
885			tmplChanged        bool
886			i18nChanged        bool
887			needsPagesAssemble bool
888		)
889	
890		changedPaths := struct {
891			changedFiles []*paths.Path
892			addedFiles   []*paths.Path
893			changedDirs  []*paths.Path
894			deleted      []*paths.Path
895		}{}
896	
897		removeDuplicatePaths := func(ps []*paths.Path) []*paths.Path {
898			seen := make(map[string]bool)
899			var filtered []*paths.Path
900			for _, p := range ps {
901				if !seen[p.Path()] {
902					seen[p.Path()] = true
903					filtered = append(filtered, p)
904				}
905			}
906			return filtered
907		}
908	
909		var (
910			cacheBusters      []func(string) bool
911			deletedDirs       []string
912			addedContentPaths []*paths.Path
913		)
914	
915		var (
916			addedOrChangedContent []pathChange
917			changes               []identity.Identity
918		)
919	
920		for _, ev := range eventInfos {
921			cpss := h.BaseFs.ResolvePaths(ev.Name)
922			pss := make([]*paths.Path, len(cpss))
923			for i, cps := range cpss {
924				p := cps.Path
925				if ev.removed && !paths.HasExt(p) {
926					// Assume this is a renamed/removed directory.
927					// For deletes, we walk up the tree to find the container (e.g. branch bundle),
928					// so we will catch this even if it is a file without extension.
929					// This avoids us walking up to the home page bundle for the common case
930					// of renaming root sections.
931					p = p + "/_index.md"
932					deletedDirs = append(deletedDirs, cps.Path)
933				}
934	
935				pss[i] = h.Configs.ContentPathParser.Parse(cps.Component, p)
936				if ev.added && !ev.isChangedDir && cps.Component == files.ComponentFolderContent {
937					addedContentPaths = append(addedContentPaths, pss[i])
938				}
939	
940				// Compile cache buster.
941				np := hglob.NormalizePath(path.Join(cps.Component, cps.Path))
942				g, err := h.ResourceSpec.BuildConfig().MatchCacheBuster(h.Log, np)
943				if err == nil && g != nil {
944					cacheBusters = append(cacheBusters, g)
945				}
946	
947				if ev.added {
948					changes = append(changes, identity.StructuralChangeAdd)
949				}
950				if ev.removed {
951					changes = append(changes, identity.StructuralChangeRemove)
952				}
953			}
954	
955			if ev.removed {
956				changedPaths.deleted = append(changedPaths.deleted, pss...)
957			} else if ev.isChangedDir {
958				changedPaths.changedDirs = append(changedPaths.changedDirs, pss...)
959			} else if ev.added {
960				changedPaths.addedFiles = append(changedPaths.addedFiles, pss...)
961			} else {
962				changedPaths.changedFiles = append(changedPaths.changedFiles, pss...)
963			}
964		}
965	
966		// Find the most specific identity possible.
967		handleChange := func(pathInfo *paths.Path, delete, add, isDir bool) {
968			switch pathInfo.Component() {
969			case files.ComponentFolderContent:
970				logger.Println("Source changed", pathInfo.Path())
971				isContentDataFile := pathInfo.IsContentData()
972				if !isContentDataFile {
973					if ids := h.pageTrees.collectAndMarkStaleIdentities(pathInfo); len(ids) > 0 {
974						changes = append(changes, ids...)
975					}
976				} else {
977					h.pageTrees.treePagesFromTemplateAdapters.DeleteAllFunc(pathInfo.Base(),
978						func(s string, n *pagesfromdata.PagesFromTemplate) bool {
979							changes = append(changes, n.DependencyManager)
980	
981							// Try to open the file to see if has been deleted.
982							f, err := n.GoTmplFi.Meta().Open()
983							if err == nil {
984								f.Close()
985							}
986	
987							if err != nil {
988								// Remove all pages and resources below.
989								prefix := paths.AddTrailingSlash(pathInfo.Base())
990	
991								h.pageTrees.treePages.DeletePrefixRaw(prefix)
992								h.pageTrees.resourceTrees.DeletePrefixRaw(prefix)
993								changes = append(changes, hglob.NewGlobIdentity(prefix+"**"))
994							}
995							return err != nil
996						})
997				}
998	
999				needsPagesAssemble = true
1000	
1001				if config.RecentlyTouched != nil {
1002					// Fast render mode. Adding them to the visited queue
1003					// avoids rerendering them on navigation.
1004					for _, id := range changes {
1005						if p, ok := id.(page.Page); ok {
1006							config.RecentlyTouched.Add(p.RelPermalink())
1007						}
1008					}
1009				}
1010	
1011				h.pageTrees.treeTaxonomyEntries.DeletePrefix("")
1012	
1013				if delete && !isContentDataFile {
1014					_, ok := h.pageTrees.treePages.LongestPrefixRaw(pathInfo.Base())
1015					if ok {
1016						h.pageTrees.treePages.DeletePrefixRaw(pathInfo.Base())
1017						h.pageTrees.resourceTrees.DeletePrefixRaw(pathInfo.Base())
1018						if pathInfo.IsBundle() {
1019							// Assume directory removed.
1020							h.pageTrees.treePages.DeletePrefixRaw(pathInfo.Base() + "/")
1021							h.pageTrees.resourceTrees.DeletePrefixRaw(pathInfo.Base() + "/")
1022						}
1023					} else {
1024						h.pageTrees.resourceTrees.DeletePrefixRaw(pathInfo.Base())
1025					}
1026				}
1027	
1028				structural := delete
1029				structural = structural || (add && pathInfo.IsLeafBundle())
1030	
1031				addedOrChangedContent = append(addedOrChangedContent, pathChange{p: pathInfo, structural: structural, isDir: isDir})
1032	
1033			case files.ComponentFolderLayouts:
1034				tmplChanged = true
1035				templatePath := pathInfo.Unnormalized().TrimLeadingSlash().PathNoLang()
1036				if !h.GetTemplateStore().HasTemplate(templatePath) {
1037					tmplAdded = true
1038				}
1039	
1040				if tmplAdded {
1041					logger.Println("Template added", pathInfo.Path())
1042					// A new template may require a more coarse grained build.
1043					base := pathInfo.Base()
1044					if strings.Contains(base, "_markup") {
1045						// It's hard to determine the exact change set of this,
1046						// so be very coarse grained.
1047						changes = append(changes, identity.GenghisKhan)
1048					}
1049					if strings.Contains(base, "shortcodes") {
1050						// Add both the shortcode file itself (for template refresh) and a glob for dependent content
1051						changes = append(changes, pathInfo)
1052						changes = append(changes, hglob.NewGlobIdentity(fmt.Sprintf("/_shortcodes/%s*", pathInfo.BaseNameNoIdentifier())))
1053					} else {
1054						changes = append(changes, pathInfo)
1055					}
1056				} else {
1057					logger.Println("Template changed", pathInfo.Path())
1058					id := h.GetTemplateStore().GetIdentity(pathInfo.Path())
1059					if id != nil {
1060						changes = append(changes, id)
1061					} else {
1062						changes = append(changes, pathInfo)
1063					}
1064				}
1065			case files.ComponentFolderAssets:
1066				logger.Println("Asset changed", pathInfo.Path())
1067				changes = append(changes, pathInfo)
1068			case files.ComponentFolderData:
1069				logger.Println("Data changed", pathInfo.Path())
1070	
1071				// This should cover all usage of hugo.Data.
1072				// Currently very coarse grained.
1073				changes = append(changes, siteidentities.Data)
1074				h.init.data.Reset()
1075			case files.ComponentFolderI18n:
1076				logger.Println("i18n changed", pathInfo.Path())
1077				i18nChanged = true
1078				// It's hard to determine the exact change set of this,
1079				// so be very coarse grained for now.
1080				changes = append(changes, identity.GenghisKhan)
1081			case files.ComponentFolderArchetypes:
1082				// Ignore for now.
1083			default:
1084				panic(fmt.Sprintf("unknown component: %q", pathInfo.Component()))
1085			}
1086		}
1087	
1088		changedPaths.deleted = removeDuplicatePaths(changedPaths.deleted)
1089		changedPaths.addedFiles = removeDuplicatePaths(changedPaths.addedFiles)
1090		changedPaths.changedFiles = removeDuplicatePaths(changedPaths.changedFiles)
1091	
1092		h.Log.Trace(logg.StringFunc(func() string {
1093			var sb strings.Builder
1094			sb.WriteString("Resolved paths:\n")
1095			sb.WriteString("Deleted:\n")
1096			for _, p := range changedPaths.deleted {
1097				sb.WriteString("path: " + p.Path())
1098				sb.WriteString("\n")
1099			}
1100			sb.WriteString("Added:\n")
1101			for _, p := range changedPaths.addedFiles {
1102				sb.WriteString("path: " + p.Path())
1103				sb.WriteString("\n")
1104			}
1105			sb.WriteString("Changed:\n")
1106			for _, p := range changedPaths.changedFiles {
1107				sb.WriteString("path: " + p.Path())
1108				sb.WriteString("\n")
1109			}
1110			return sb.String()
1111		}))
1112	
1113		for _, deletedDir := range deletedDirs {
1114			prefix := deletedDir + "/"
1115			predicate := func(id identity.Identity) bool {
1116				// This will effectively reset all pages below this dir.
1117				return strings.HasPrefix(paths.AddLeadingSlash(id.IdentifierBase()), prefix)
1118			}
1119			// Test in both directions.
1120			changes = append(changes, identity.NewPredicateIdentity(
1121				// Is dependent.
1122				predicate,
1123				// Is dependency.
1124				predicate,
1125			),
1126			)
1127		}
1128	
1129		if len(addedContentPaths) > 0 {
1130			// These content files are new and not in use anywhere.
1131			// To make sure that these gets listed in any site.RegularPages ranges or similar
1132			// we could invalidate everything, but first try to collect a sample set
1133			// from the surrounding pages.
1134			var surroundingIDs []identity.Identity
1135			for _, p := range addedContentPaths {
1136				if ids := h.pageTrees.collectIdentitiesSurrounding(p.Base(), 10); len(ids) > 0 {
1137					surroundingIDs = append(surroundingIDs, ids...)
1138				}
1139			}
1140	
1141			if len(surroundingIDs) > 0 {
1142				changes = append(changes, surroundingIDs...)
1143			} else {
1144				// No surrounding pages found, so invalidate everything.
1145				changes = append(changes, identity.GenghisKhan)
1146			}
1147		}
1148	
1149		for _, deleted := range changedPaths.deleted {
1150			handleChange(deleted, true, false, false)
1151		}
1152	
1153		for _, id := range changedPaths.addedFiles {
1154			handleChange(id, false, true, false)
1155		}
1156	
1157		for _, id := range changedPaths.changedFiles {
1158			handleChange(id, false, false, false)
1159		}
1160	
1161		for _, id := range changedPaths.changedDirs {
1162			handleChange(id, false, false, true)
1163		}
1164	
1165		for _, id := range changes {
1166			if id == identity.GenghisKhan {
1167				for i, cp := range addedOrChangedContent {
1168					cp.structural = true
1169					addedOrChangedContent[i] = cp
1170				}
1171				break
1172			}
1173		}
1174	
1175		resourceFiles := h.fileEventsContentPaths(addedOrChangedContent)
1176	
1177		changed := &WhatChanged{
1178			needsPagesAssembly: needsPagesAssemble,
1179		}
1180		changed.Add(changes...)
1181	
1182		config.WhatChanged = changed
1183	
1184		if err := init(config); err != nil {
1185			return err
1186		}
1187	
1188		var cacheBusterOr func(string) bool
1189		if len(cacheBusters) > 0 {
1190			cacheBusterOr = func(s string) bool {
1191				for _, cb := range cacheBusters {
1192					if cb(s) {
1193						return true
1194					}
1195				}
1196				return false
1197			}
1198		}
1199	
1200		changes2 := changed.Changes()
1201		h.Deps.OnChangeListeners.Notify(changes2...)
1202	
1203		if err := h.resolveAndClearStateForIdentities(ctx, l, cacheBusterOr, changed.Drain()); err != nil {
1204			return err
1205		}
1206	
1207		if tmplChanged {
1208			if err := loggers.TimeTrackfn(func() (logg.LevelLogger, error) {
1209				depsFinder := identity.NewFinder(identity.FinderConfig{})
1210				ll := l.WithField("substep", "rebuild templates")
1211				s := h.Sites[0]
1212				if err := s.Deps.TemplateStore.RefreshFiles(func(fi hugofs.FileMetaInfo) bool {
1213					pi := fi.Meta().PathInfo
1214					for _, id := range changes2 {
1215						if depsFinder.Contains(pi, id, -1) > 0 {
1216							return true
1217						}
1218					}
1219					return false
1220				}); err != nil {
1221					return ll, err
1222				}
1223	
1224				return ll, nil
1225			}); err != nil {
1226				return err
1227			}
1228		}
1229	
1230		if i18nChanged {
1231			if err := loggers.TimeTrackfn(func() (logg.LevelLogger, error) {
1232				ll := l.WithField("substep", "rebuild i18n")
1233				var prototype *deps.Deps
1234				for i, s := range h.Sites {
1235					if err := s.Deps.Compile(prototype); err != nil {
1236						return ll, err
1237					}
1238					if i == 0 {
1239						prototype = s.Deps
1240					}
1241				}
1242				return ll, nil
1243			}); err != nil {
1244				return err
1245			}
1246		}
1247	
1248		if resourceFiles != nil {
1249			if err := h.processFiles(ctx, l, config, resourceFiles...); err != nil {
1250				return err
1251			}
1252		}
1253	
1254		if h.isRebuild() {
1255			if err := h.processContentAdaptersOnRebuild(ctx, config); err != nil {
1256				return err
1257			}
1258		}
1259	
1260		return nil
1261	}
