276	// renderPaginator must be run after the owning Page has been rendered.
277	func (s *Site) renderPaginator(p *pageState, templ *tplimpl.TemplInfo) error {
278		paginatePath := s.Conf.Pagination().Path
279	
280		d := p.targetPathDescriptor
281		f := p.outputFormat()
282		d.Type = f
283	
284		if p.paginator.current == nil || p.paginator.current != p.paginator.current.First() {
285			panic(fmt.Sprintf("invalid paginator state for %q", p.pathOrTitle()))
286		}
287	
288		if f.IsHTML && !s.Conf.Pagination().DisableAliases {
289			// Write alias for page 1
290			d.Addends = fmt.Sprintf("/%s/%d", paginatePath, 1)
291			targetPaths := page.CreateTargetPaths(d)
292	
293			if err := s.writeDestAlias(targetPaths.TargetFilename, p.Permalink(), f, p); err != nil {
294				return err
295			}
296	
297		}
298	
299		// Render pages for the rest
300		for current := p.paginator.current.Next(); current != nil; current = current.Next() {
301	
302			p.paginator.current = current
303			d.Addends = fmt.Sprintf("/%s/%d", paginatePath, current.PageNumber())
304			targetPaths := page.CreateTargetPaths(d)
305	
306			if err := s.renderAndWritePage(
307				&s.PathSpec.ProcessingStats.PaginatorPages,
308				targetPaths.TargetFilename, p, p, templ); err != nil {
309				return err
310			}
311	
312		}
313	
314		return nil
315	}
