317	func (s *Site) renderAliasesForPage(p *pageState) error {
318		po := p.pageOutput
319		f := po.f
320		plink := p.Permalink()
321		for _, a := range p.Aliases() {
322			err := s.writeDestAlias(a, plink, f, p)
323			if err != nil {
324				return err
325			}
326		}
327		return nil
328	}
