69	// renderPages renders pages concurrently.
70	func (s *Site) renderPages(ctx *siteRenderContext) error {
71		numWorkers := config.GetNumWorkerMultiplier()
72	
73		results := make(chan error)
74		pages := make(chan *pageState, numWorkers) // buffered for performance
75		errs := make(chan error)
76	
77		go s.errorCollator(results, errs)
78	
79		wg := &sync.WaitGroup{}
80	
81		for range numWorkers {
82			wg.Add(1)
83			go pageRenderer(ctx, s, pages, results, wg)
84		}
85	
86		cfg := ctx.cfg
87	
88		w := &doctree.NodeShiftTreeWalker[contentNode]{
89			Tree: s.pageMap.treePages,
90			Handle: func(key string, n contentNode) (radix.WalkFlag, error) {
91				if p, ok := n.(*pageState); ok {
92					if cfg.shouldRender(ctx.infol, p) {
93						select {
94						case <-s.h.Done():
95							return radix.WalkStop, nil
96						default:
97							pages <- p
98						}
99					}
100				}
101				return radix.WalkContinue, nil
102			},
103		}
104	
105		if err := w.Walk(context.Background()); err != nil {
106			return err
107		}
108	
109		close(pages)
110	
111		wg.Wait()
112	
113		close(results)
114	
115		err := <-errs
116		if err != nil {
117			return fmt.Errorf("%v failed to render pages: %w", s.resolveDimensionNames(), err)
118		}
119		return nil
120	}
121	
122	func pageRenderer(
123		ctx *siteRenderContext,
124		s *Site,
125		pages <-chan *pageState,
126		results chan<- error,
127		wg *sync.WaitGroup,
128	) {
129		defer wg.Done()
130	
131		sendErr := func(err error) bool {
132			select {
133			case results <- err:
134				return true
135			case <-s.h.Done():
136				return false
137			}
138		}
139	
140		for p := range pages {
141	
142			if p.m.isStandalone() && !ctx.shouldRenderStandalonePage(p.Kind()) {
143				continue
144			}
145	
146			if p.m.pageConfig.Build.PublishResources {
147				if err := p.renderResources(); err != nil {
148					if sendErr(p.errorf(err, "failed to render resources")) {
149						continue
150					} else {
151						return
152					}
153				}
154			}
155	
156			if !s.conf.DisableAliases && !s.h.BuildState.IsRebuild() && p.render {
157				of := p.outputFormat()
158				if of.IsHTML && of.Permalinkable {
159					// Render any aliases for this page.
160					if err := s.renderAliasesForPage(p); err != nil {
161						if sendErr(err) {
162							continue
163						} else {
164							return
165						}
166					}
167				}
168			}
169	
170			if !p.render {
171				// Nothing more to do for this page.
172				continue
173			}
174	
175			templ, found, err := p.resolveTemplate()
176			if err != nil {
177				if sendErr(p.errorf(err, "failed to resolve template")) {
178					continue
179				} else {
180					return
181				}
182			}
183	
184			if !found {
185				s.Log.Trace(
186					func() string {
187						return fmt.Sprintf("no layout for kind %q found", p.Kind())
188					},
189				)
190				// Don't emit warning for missing 404 etc. pages.
191				if !p.m.isStandalone() {
192					s.logMissingLayout("", p.Layout(), p.Kind(), p.f.Name)
193				}
194				continue
195			}
196	
197			targetPath := p.targetPaths().TargetFilename
198	
199			s.Log.Trace(
200				func() string {
201					return fmt.Sprintf("rendering outputFormat %q kind %q using layout %q to %q", p.pageOutput.f.Name, p.Kind(), templ.Name(), targetPath)
202				},
203			)
204	
205			var d any = p
206			switch p.Kind() {
207			case kinds.KindSitemapIndex:
208				d = s.h.Sites
209			}
210	
211			if err := s.renderAndWritePage(&s.PathSpec.ProcessingStats.Pages, targetPath, p, d, templ); err != nil {
212				if sendErr(err) {
213					continue
214				} else {
215					return
216				}
217			}
218	
219			if of := p.outputFormat(); p.IsHome() && of.IsHTML && s.isDefault() && (of.Path != "" || of.Name == "html") {
220				if err = s.renderDefaultSiteRedirect(p); err != nil {
221					if sendErr(err) {
222						continue
223					} else {
224						return
225					}
226				}
227			}
228	
229			if p.paginator != nil && p.paginator.current != nil {
230				if err := s.renderPaginator(p, templ); err != nil {
231					if sendErr(err) {
232						continue
233					} else {
234						return
235					}
236				}
237			}
238		}
239	}
