329	// renderDefaultSiteRedirect creates a redirect to the default site's home,
330	// depending on if it lives in sub folder (e.g. /en) or not.
331	// The default site is the site is the combination of defaultContentLanguage,
332	// defaultContentVersion and defaultContentRole.
333	func (s *Site) renderDefaultSiteRedirect(home *pageState) error {
334		if s.conf.DisableDefaultLanguageRedirect || s.conf.DisableDefaultSiteRedirect {
335			return nil
336		}
337	
338		addRedirectInRoot := s.conf.DefaultContentLanguageInSubdir && !s.Conf.IsMultihost()
339		addRedirectInRoot = addRedirectInRoot || s.conf.DefaultContentVersionInSubdir || s.conf.DefaultContentRoleInSubdir
340	
341		homeLink := home.pageOutput.targetPaths().Link // This doesn't have any baseURL paths in it.
342	
343		of := home.outputFormat()
344		homePermalink := home.Permalink()
345	
346		var ps []string
347		if of.Path != "" {
348			if addRedirectInRoot {
349				// For OutputFormats with a path, creating more than one alias will easily create path clashes without much value.
350				ps = []string{paths.AddLeadingAndTrailingSlash(of.Path)}
351			}
352		} else {
353			if addRedirectInRoot {
354				ps = append(ps, "/")
355			}
356	
357			if s.Conf.IsMultilingual() && !s.conf.DefaultContentLanguageInSubdir && !s.Conf.IsMultihost() {
358				// Create redirect from e.g. /en => /
359				ps = append(ps, homeLink+s.Lang()+"/")
360			}
361	
362			// /guest/v1.0.0/en/
363			//    /,/guest/,/guest/v1.0.0  = /guest/v1.0.0/en/
364			// /guest/v1.0.0/
365			//    /,/guest/ =  /guest/v1.0.0/
366			parts := strings.Split(strings.Trim(homeLink, "/"), "/")
367	
368			for i := 0; i < len(parts)-1; i++ {
369				ps = append(ps, paths.AddLeadingAndTrailingSlash(strings.Join(parts[0:i+1], "/")))
370			}
371		}
372	
373		if s.h.Configs.IsMultihost {
374			prefix := "/" + s.LanguagePrefix()
375			for i, p := range ps {
376				ps[i] = path.Join(prefix, p)
377			}
378		}
379	
380		for _, p := range ps {
381			if err := s.publishDestAlias(true, p, homePermalink, of, home); err != nil {
382				return err
383			}
384		}
385	
386		return nil
387	}
