482	// The home page is represented with the zero string.
483	// All other keys starts with a leading slash. No trailing slash.
484	// Slashes are Unix-style.
485	func cleanTreeKey(elem ...string) string {
486		var s string
487		if len(elem) > 0 {
488			s = elem[0]
489			if len(elem) > 1 {
490				s = path.Join(elem...)
491			}
492		}
493		s = strings.TrimFunc(s, trimCutsetDotSlashSpace)
494		s = filepath.ToSlash(strings.ToLower(paths.Sanitize(s)))
495		if s == "" || s == "/" {
496			return ""
497		}
498		if s[0] != '/' {
499			s = "/" + s
500		}

