159	// allSites will range over all sites in the order of the sitesVersionsRoles matrix.
160	// If include is not nil, it will be used to filter the sites.
161	func (h *HugoSites) allSites(include func(s *Site) bool) iter.Seq[*Site] {
162		if include == nil {
163			include = func(s *Site) bool {
164				return true
165			}
166		}
167		return func(yield func(s *Site) bool) {
168			for _, v := range h.sitesVersionsRoles {
169				for _, r := range v {
170					for _, s := range r {
171						if !include(s) {
172							continue
173						}
174						if !yield(s) {
175							return
176						}
177					}
178				}
179			}
180		}
181	}
182	
183	// allSitesInterface is the same as allSites but returns page.Site, which is used in some places where we don't want to expose the full *Site type.
184	// If include is not nil, it will be used to filter the sites.
185	func (h *HugoSites) allSitesInterface(include func(s page.Site) bool) iter.Seq[page.Site] {
186		if include == nil {
187			include = func(s page.Site) bool {
188				return true
189			}
190		}
191		return func(yield func(s page.Site) bool) {
192			for _, v := range h.sitesVersionsRoles {
193				for _, r := range v {
194					for _, s := range r {
195						if !include(s) {
196							continue
197						}
198						// Site() returns a wrapped version of the site that only exposes the page.Site interface.
199						if !yield(s.Site()) {
200							return
201						}
202					}
203				}
204			}
205		}
206	}
207	
208	// allSiteLanguages will range over the first site in each language that's not skipped.
209	func (h *HugoSites) allSiteLanguages(include func(s *Site) bool) iter.Seq[*Site] {
210		return func(yield func(s *Site) bool) {
211		LOOP:
212			for _, v := range h.sitesVersionsRoles {
213				for _, r := range v {
214					for _, s := range r {
215						if include != nil && !include(s) {
216							continue LOOP
217						}
218						if !yield(r[0]) {
219							return
220						}
221						continue LOOP
222					}
223				}
224			}
225		}
226	}
