456	func (ps *pageState) String() string {
457		var sb strings.Builder
458		if ps.File() != nil {
459			// The forward slashes even on Windows is motivated by
460			// getting stable tests.
461			// This information is meant for getting positional information in logs,
462			// so the direction of the slashes should not matter.
463			sb.WriteString(filepath.ToSlash(ps.File().Filename()))
464			if ps.File().IsContentAdapter() {
465				// Also include the path.
466				sb.WriteString(":")
467				sb.WriteString(ps.Path())
468			}
469		} else {
470			sb.WriteString(ps.Path())
471		}
472		return sb.String()
473	}
