537	// Rotate returns all pages in the given dimension for this page.
538	func (ps *pageState) Rotate(dimensionStr string) (page.Pages, error) {
539		dimensionStr = strings.ToLower(dimensionStr)
540		key := ps.Path() + "/" + "rotate-" + dimensionStr
541		d, err := sitesmatrix.ParseDimension(dimensionStr)
542		if err != nil {
543			return nil, fmt.Errorf("failed to parse dimension %q: %w", dimensionStr, err)
544		}
545	
546		pages, err := ps.s.pageMap.getOrCreatePagesFromCache(ps.s.pageMap.cachePages2, key, func(string) (page.Pages, error) {
547			var pas page.Pages
548			ps.s.pageMap.treePages.ForEeachInDimension(ps.Path(), ps.s.siteVector, d,
549				func(n contentNode) bool {
550					if n != nil {
551						p := n.(page.Page)
552						pas = append(pas, p)
553					}
554					return true
555				},
556			)
557	
558			if dimensionStr == "language" && ps.m.pageConfig.TranslationKey != "" {
559				// translationKey set by user.
560				// This is an old construct back from when languages were introduced.
561				// We keep it for backward compatibility.
562				// Also see AllTranslations.
563				pas, _ := ps.s.h.translationKeyPages.Get(ps.m.pageConfig.TranslationKey)
564				pasc := slices.Clone(pas)
565				page.SortByLanguage(pasc)
566				return pasc, nil
567			}
568	
569			pas = pagePredicates.ShouldLink.Filter(pas)
570			page.SortByDims(pas)
571			return pas, nil
572		})
573	
574		return pages, err
