869	// shiftToOutputFormat is serialized. The output format idx refers to the
870	// full set of output formats for all sites.
871	// This is serialized.
872	func (ps *pageState) shiftToOutputFormat(isRenderingSite bool, idx int) error {
873		if err := ps.initPage(); err != nil {
874			return err
875		}
876	
877		if len(ps.pageOutputs) == 1 {
878			idx = 0
879		}
880	
881		ps.pageOutputIdx = idx
882		ps.pageOutput = ps.pageOutputs[idx]
883		if ps.pageOutput == nil {
884			panic(fmt.Sprintf("pageOutput is nil for output idx %d", idx))
885		}
886	
887		// Reset any built paginator. This will trigger when re-rendering pages in
888		// server mode.
889		if isRenderingSite && ps.pageOutput.paginator != nil && ps.pageOutput.paginator.current != nil {
890			ps.pageOutput.paginator.reset()
891		}
892	
893		if isRenderingSite {
894			cp := ps.pageOutput.pco
895			if cp == nil && ps.canReusePageOutputContent() {
896				// Look for content to reuse.
897				for i := range ps.pageOutputs {
898					if i == idx {
899						continue
900					}
901					po := ps.pageOutputs[i]
902	
903					if po.pco != nil {
904						cp = po.pco
905						break
906					}
907				}
908			}
909	
910			if cp == nil {
911				var err error
912				cp, err = newPageContentOutput(ps.pageOutput)
913				if err != nil {
914					return err
915				}
916			}
917			ps.pageOutput.setContentProvider(cp)
918		} else {
919			// We attempt to assign pageContentOutputs while preparing each site
920			// for rendering and before rendering each site. This lets us share
921			// content between page outputs to conserve resources. But if a template
922			// unexpectedly calls a method of a ContentProvider that is not yet
923			// initialized, we assign a LazyContentProvider that performs the
924			// initialization just in time.
925			if lcp, ok := (ps.pageOutput.ContentProvider.(*page.LazyContentProvider)); ok {
926				lcp.Reset()
927			} else {
928				lcp = page.NewLazyContentProvider(func(context.Context) page.OutputFormatContentProvider {
929					cp, err := newPageContentOutput(ps.pageOutput)
930					if err != nil {
931						panic(err)
932					}
933					return cp
934				})
935	
936				ps.pageOutput.contentRenderer = lcp
937				ps.pageOutput.ContentProvider = lcp
938				ps.pageOutput.MarkupProvider = lcp
939				ps.pageOutput.PageRenderProvider = lcp
940				ps.pageOutput.TableOfContentsProvider = lcp
941			}
942		}
943	
944		return nil
945	}
