253	func (ps *pageState) lookupContentNodes(vec sitesmatrix.Vector, fallback bool) iter.Seq[contentNodeForSite] {
254		nop := func(yield func(n contentNodeForSite) bool) {}
255		pc := ps.m.pageConfigSource
256		if !fallback {
257			if !pc.MatchSiteVector(vec) {
258				return nop
259			}
260			return func(yield func(n contentNodeForSite) bool) {
261				yield(ps)
262			}
263		}
264	
265		if !pc.MatchLanguageCoarse(vec) {
266			return nop
267		}
268	
269		if !pc.MatchVersionCoarse(vec) {
270			return nop
271		}
272		if !pc.MatchRoleCoarse(vec) {
273			return nop
274		}
275	
276		return func(yield func(n contentNodeForSite) bool) {
277			yield(ps)
278		}
279	}
