488	// AllTranslations returns all translations, including the current Page.
489	func (ps *pageState) AllTranslations() page.Pages {
490		key := ps.Path() + "/" + "translations-all"
491		// This is called from Translations, so we need to use a different partition, cachePages2,
492		// to avoid potential deadlocks.
493		pages, err := ps.s.pageMap.getOrCreatePagesFromCache(ps.s.pageMap.cachePages2, key, func(string) (page.Pages, error) {
494			if ps.m.pageConfig.TranslationKey != "" {
495				// translationKey set by user.
496				pas, _ := ps.s.h.translationKeyPages.Get(ps.m.pageConfig.TranslationKey)
497				pasc := slices.Clone(pas)
498				page.SortByLanguage(pasc)
499				return pasc, nil
500			}
501			var pas page.Pages
502	
503			ps.s.pageMap.treePages.ForEeachInDimension(ps.Path(), ps.s.siteVector, sitesmatrix.Language,
504				func(n contentNode) bool {
505					if n != nil {
506						pas = append(pas, n.(page.Page))
507					}
508					return true
509				},
510			)
511	
512			pas = pagePredicates.ShouldLink.Filter(pas)
513			page.SortByLanguage(pas)
514			return pas, nil
515		})
516		if err != nil {
517			panic(err)
518		}
519	
520		return pages
521	}
