536	// Rotate returns all pages in the given dimension for this page.
537	func (ps *pageState) Rotate(dimensionStr string) (page.Pages, error) {
538		dimensionStr = strings.ToLower(dimensionStr)
539		key := ps.Path() + "/" + "rotate-" + dimensionStr
540		d, err := sitesmatrix.ParseDimension(dimensionStr)
541		if err != nil {
542			return nil, fmt.Errorf("failed to parse dimension %q: %w", dimensionStr, err)
543		}
544	
545		pages, err := ps.s.pageMap.getOrCreatePagesFromCache(ps.s.pageMap.cachePages2, key, func(string) (page.Pages, error) {
546			var pas page.Pages
547			ps.s.pageMap.treePages.ForEeachInDimension(ps.Path(), ps.s.siteVector, d,
548				func(n contentNode) bool {
549					if n != nil {
550						p := n.(page.Page)
551						pas = append(pas, p)
552					}
553					return true
554				},
555			)
556	
557			if dimensionStr == "language" && ps.m.pageConfig.TranslationKey != "" {
558				// translationKey set by user.
559				// This is an old construct back from when languages were introduced.
560				// We keep it for backward compatibility.
561				// Also see AllTranslations.
562				pas, _ := ps.s.h.translationKeyPages.Get(ps.m.pageConfig.TranslationKey)
563				pasc := slices.Clone(pas)
564				page.SortByLanguage(pasc)
565				return pasc, nil
566			}
567	
568			pas = pagePredicates.ShouldLink.Filter(pas)
569			page.SortByDims(pas)
570			return pas, nil
571		})
572	
573		return pages, err
574	}
