629	func (ps *pageState) resolveTemplate(layouts ...string) (*tplimpl.TemplInfo, bool, error) {
630		dir, d := ps.GetInternalTemplateBasePathAndDescriptor()
631	
632		if len(layouts) > 0 {
633			d.LayoutFromUser = layouts[0]
634			d.LayoutFromUserMustMatch = true
635		}
636	
637		q := tplimpl.TemplateQuery{
638			Path:     dir,
639			Category: tplimpl.CategoryLayout,
640			Sites:    ps.s.siteVector,
641			Desc:     d,
642		}
643	
644		tinfo := ps.s.TemplateStore.LookupPagesLayout(q)
645		if tinfo == nil {
646			return nil, false, nil
647		}
648	
649		return tinfo, true, nil
650	}
