652	// Must be run after the site section tree etc. is built and ready.
653	func (ps *pageState) initPage() error {
654		var initErr error
655		ps.pageInit.Do(func() {
656			var pp pagePaths
657			pp, initErr = newPagePaths(ps)
658			if initErr != nil {
659				return
660			}
661	
662			var outputFormatsForPage output.Formats
663			var renderFormats output.Formats
664	
665			if ps.m.standaloneOutputFormat.IsZero() {
666				outputFormatsForPage = ps.outputFormats()
667				renderFormats = ps.s.h.renderFormats
668			} else {
669				// One of the fixed output format pages, e.g. 404.
670				outputFormatsForPage = output.Formats{ps.m.standaloneOutputFormat}
671				renderFormats = outputFormatsForPage
672			}
673	
674			// Prepare output formats for all sites.
675			// We do this even if this page does not get rendered on
676			// its own. It may be referenced via one of the site collections etc.
677			// it will then need an output format.
678			ps.pageOutputs = make([]*pageOutput, len(renderFormats))
679			created := make(map[string]*pageOutput)
680			shouldRenderPage := !ps.m.noRender()
681	
682			for i, f := range renderFormats {
683	
684				if po, found := created[f.Name]; found {
685					ps.pageOutputs[i] = po
686					continue
687				}
688	
689				render := shouldRenderPage
690				if render {
691					_, render = outputFormatsForPage.GetByName(f.Name)
692				}
693	
694				po := newPageOutput(ps, pp, f, render)
695	
696				// Create a content provider for the first,
697				// we may be able to reuse it.
698				if i == 0 {
699					var contentProvider *pageContentOutput
700					contentProvider, initErr = newPageContentOutput(po)
701					if initErr != nil {
702						return
703					}
704					po.setContentProvider(contentProvider)
705				}
706	
707				ps.pageOutputs[i] = po
708				created[f.Name] = po
709	
710			}
711	
712			if initErr = ps.initCommonProviders(pp); initErr != nil {
713				return
714			}
715		})
716	
717		return initErr
718	}
