720	func (ps *pageState) renderResources() error {
721		for _, r := range ps.Resources() {
722			if _, ok := r.(page.Page); ok {
723				if !ps.s.h.BuildState.IsRebuild() {
724					// Pages gets rendered with the owning page but we count them here.
725					ps.s.PathSpec.ProcessingStats.Incr(&ps.s.PathSpec.ProcessingStats.Pages)
726				}
727				continue
728			}
729	
730			if resources.IsPublished(r) {
731				continue
732			}
733	
734			src, ok := r.(resource.Source)
735			if !ok {
736				return fmt.Errorf("resource %T does not support resource.Source", r)
737			}
738	
739			if err := src.Publish(); err != nil {
740				if !herrors.IsNotExist(err) {
741					ps.s.Log.Errorf("Failed to publish Resource for page %q: %s", ps.pathOrTitle(), err)
