868	// shiftToOutputFormat is serialized. The output format idx refers to the
869	// full set of output formats for all sites.
870	// This is serialized.
871	func (ps *pageState) shiftToOutputFormat(isRenderingSite bool, idx int) error {
872		if err := ps.initPage(); err != nil {
873			return err
874		}
875	
876		if len(ps.pageOutputs) == 1 {
877			idx = 0
878		}
879	
880		ps.pageOutputIdx = idx
881		ps.pageOutput = ps.pageOutputs[idx]
882		if ps.pageOutput == nil {
883			panic(fmt.Sprintf("pageOutput is nil for output idx %d", idx))
884		}
885	
886		// Reset any built paginator. This will trigger when re-rendering pages in
887		// server mode.
888		if isRenderingSite && ps.pageOutput.paginator != nil && ps.pageOutput.paginator.current != nil {
889			ps.pageOutput.paginator.reset()
890		}
891	
892		if isRenderingSite {
893			cp := ps.pageOutput.pco
894			if cp == nil && ps.canReusePageOutputContent() {
895				// Look for content to reuse.
896				for i := range ps.pageOutputs {
897					if i == idx {
898						continue
899					}
900					po := ps.pageOutputs[i]
901	
902					if po.pco != nil {
903						cp = po.pco
904						break
905					}
906				}
907			}
908	
909			if cp == nil {
910				var err error
911				cp, err = newPageContentOutput(ps.pageOutput)
912				if err != nil {
913					return err
914				}
915			}
916			ps.pageOutput.setContentProvider(cp)
917		} else {
918			// We attempt to assign pageContentOutputs while preparing each site
919			// for rendering and before rendering each site. This lets us share
920			// content between page outputs to conserve resources. But if a template
921			// unexpectedly calls a method of a ContentProvider that is not yet
922			// initialized, we assign a LazyContentProvider that performs the
923			// initialization just in time.
924			if lcp, ok := (ps.pageOutput.ContentProvider.(*page.LazyContentProvider)); ok {
925				lcp.Reset()
926			} else {
927				lcp = page.NewLazyContentProvider(func(context.Context) page.OutputFormatContentProvider {
928					cp, err := newPageContentOutput(ps.pageOutput)
929					if err != nil {
930						panic(err)
931					}
932					return cp
933				})
934	
935				ps.pageOutput.contentRenderer = lcp
936				ps.pageOutput.ContentProvider = lcp
937				ps.pageOutput.MarkupProvider = lcp
938				ps.pageOutput.PageRenderProvider = lcp
939				ps.pageOutput.TableOfContentsProvider = lcp
940			}
941		}
942	
943		return nil
944	}
