122	func pageRenderer(
123		ctx *siteRenderContext,
124		s *Site,
125		pages <-chan *pageState,
126		results chan<- error,
127		wg *sync.WaitGroup,
128	) {
129		defer wg.Done()
130	
131		sendErr := func(err error) bool {
132			select {
133			case results <- err:
134				return true
135			case <-s.h.Done():
136				return false
137			}
138		}
139	
140		for p := range pages {
141	
142			if p.m.isStandalone() && !ctx.shouldRenderStandalonePage(p.Kind()) {
143				continue
144			}
145	
146			if p.m.pageConfig.Build.PublishResources {
147				if err := p.renderResources(); err != nil {
148					if sendErr(p.errorf(err, "failed to render resources")) {
149						continue
150					} else {
151						return
152					}
153				}
154			}
155	
156			if !s.conf.DisableAliases && !s.h.BuildState.IsRebuild() && p.render {
157				of := p.outputFormat()
158				if of.IsHTML && of.Permalinkable {
159					// Render any aliases for this page.
160					if err := s.renderAliasesForPage(p); err != nil {
161						if sendErr(err) {
162							continue
163						} else {
164							return
165						}
166					}
167				}
168			}
169	
170			if !p.render {
171				// Nothing more to do for this page.
172				continue
173			}
174	
175			templ, found, err := p.resolveTemplate()
176			if err != nil {
177				if sendErr(p.errorf(err, "failed to resolve template")) {
178					continue
179				} else {
180					return
181				}
182			}
183	
184			if !found {
185				s.Log.Trace(
186					func() string {
187						return fmt.Sprintf("no layout for kind %q found", p.Kind())
188					},
189				)
190				// Don't emit warning for missing 404 etc. pages.
191				if !p.m.isStandalone() {
192					s.logMissingLayout("", p.Layout(), p.Kind(), p.f.Name)
193				}
194				continue
195			}
196	
197			targetPath := p.targetPaths().TargetFilename
198	
199			s.Log.Trace(
200				func() string {
201					return fmt.Sprintf("rendering outputFormat %q kind %q using layout %q to %q", p.pageOutput.f.Name, p.Kind(), templ.Name(), targetPath)
202				},
203			)
204	
205			var d any = p
206			switch p.Kind() {
207			case kinds.KindSitemapIndex:
208				d = s.h.Sites
209			}
210	
211			if err := s.renderAndWritePage(&s.PathSpec.ProcessingStats.Pages, targetPath, p, d, templ); err != nil {
212				if sendErr(err) {
213					continue
214				} else {
215					return
216				}
217			}
218	
219			if of := p.outputFormat(); p.IsHome() && of.IsHTML && s.isDefault() && (of.Path != "" || of.Name == "html") {
220				if err = s.renderDefaultSiteRedirect(p); err != nil {
221					if sendErr(err) {
222						continue
223					} else {
224						return
225					}
226				}
227			}
228	
229			if p.paginator != nil && p.paginator.current != nil {
230				if err := s.renderPaginator(p, templ); err != nil {
231					if sendErr(err) {
232						continue
233					} else {
234						return
235					}
236				}
237			}
238		}
239	}
