241	func (s *Site) logMissingLayout(name, layout, kind, outputFormat string) {
242		log := s.Log.Warn()
243		if name != "" && infoOnMissingLayout[name] {
244			log = s.Log.Info()
245		}
246	
247		errMsg := "You should create a template file which matches Hugo Layouts Lookup Rules for this combination."
248		var args []any
249		msg := "found no layout file for"
250		if outputFormat != "" {
251			msg += " %q"
252			args = append(args, outputFormat)
253		}
254	
255		if layout != "" {
256			msg += " for layout %q"
257			args = append(args, layout)
258		}
259	
260		if kind != "" {
261			msg += " for kind %q"
262			args = append(args, kind)
263		}
264	
265		if name != "" {
266			msg += " for %q"
267			args = append(args, name)
268		}
269	
270		msg += ": " + errMsg
271	
272		log.Logf(msg, args...)
273	}
