275	// renderPaginator must be run after the owning Page has been rendered.
276	func (s *Site) renderPaginator(p *pageState, templ *tplimpl.TemplInfo) error {
277		paginatePath := s.Conf.Pagination().Path
278	
279		d := p.targetPathDescriptor
280		f := p.outputFormat()
281		d.Type = f
282	
283		if p.paginator.current == nil || p.paginator.current != p.paginator.current.First() {
284			panic(fmt.Sprintf("invalid paginator state for %q", p.pathOrTitle()))
285		}
286	
287		if f.IsHTML && !s.Conf.Pagination().DisableAliases {
288			// Write alias for page 1
289			d.Addends = fmt.Sprintf("/%s/%d", paginatePath, 1)
290			targetPaths := page.CreateTargetPaths(d)
291	
292			if err := s.writeDestAlias(targetPaths.TargetFilename, p.Permalink(), f, p); err != nil {
293				return err
294			}
295	
296		}
297	
298		// Render pages for the rest
299		for current := p.paginator.current.Next(); current != nil; current = current.Next() {
300	
301			p.paginator.current = current
302			d.Addends = fmt.Sprintf("/%s/%d", paginatePath, current.PageNumber())
303			targetPaths := page.CreateTargetPaths(d)
304	
305			if err := s.renderAndWritePage(
306				&s.PathSpec.ProcessingStats.PaginatorPages,
307				targetPaths.TargetFilename, p, p, templ); err != nil {
308				return err
309			}
310	
311		}
312	
313		return nil
314	}
